const fs = require\('fs'\);
const content = fs.readFileSync\('js/ui.js', 'utf8'\);
const lines = content.split\('\\n'\);
let count = 0;
const result = lines.map\(line => {
  const trimmed = line.trimEnd\(\);
  // for\(\) 루프 헤더는 건드리지 않음
  if \(trimmed.endsWith\(';'\) && !trimmed.match\(/^\\s*for\\s*\\\(/\)\) {
    count++;
    return trimmed.slice\(0, -1\);
  }
  return line;
}\);
fs.writeFileSync\('js/ui.js', result.join\('\\n'\)\);
console.log\('세미콜론 제거 완료: ' + count + '개 / ' + lines.length + '줄'\);
")
